const item = $input.first().json || {};
const isDbError = !!(item.error && typeof item.error === 'object' && item.error.message);

if (isDbError) {
  return [{
    json: {
      report: `🔴 <b>DATA RETENTION — DB ERROR</b>\n\nCleanup query failed.\n\n<b>Error:</b> <code>${String(item.error.message).substring(0, 500)}</code>\n<b>Timestamp:</b> ${new Date().toISOString()}`,
      isDbError: true,
      isLimitHit: false,
      deletedEvents: 0,
      totalEvents: 0,
      eventsTableSize: 'unknown',
      staleCircuitReset: false,
      schemaVersionPresent: false,
      expectedTablesFound: 0,
      schemaOk: false
    }
  }];
}

const deletedEvents = parseInt(item.deleted_events_count, 10) || 0;
const staleCircuitReset = item.stale_circuit_reset === true || item.stale_circuit_reset === 't';
const isLimitHit = deletedEvents >= 1000;
const totalEvents = parseInt(item.total_events, 10) || 0;
const eventsTableSize = item.events_table_size || 'unknown';
const schemaVersionPresent = (parseInt(item.schema_version_present, 10) || 0) > 0;
const expectedTablesFound = parseInt(item.expected_tables_found, 10) || 0;
const schemaOk = schemaVersionPresent && expectedTablesFound === 3;

let report = `🧹 <b>DATA RETENTION REPORT — V1 Lean</b>\n\n<b>Deleted Events older than 90d:</b> ${deletedEvents}\n<b>Remaining Events:</b> ${totalEvents}\n<b>Events Table Size:</b> ${eventsTableSize}\n<b>Schema:</b> ${schemaOk ? '✅ v1_lean present, 3/3 tables found' : `⚠️ check needed — version present: ${schemaVersionPresent ? 'yes' : 'no'}, tables found: ${expectedTablesFound}/3`}`;

if (staleCircuitReset) {
  report += '\n\n⚠️ <b>STALE CIRCUIT RESET:</b> Circuit was open for >1 hour with no new errors. Auto-reset to closed.';
}

if (isLimitHit) {
  report += '\n\n⚠️ <b>LIMIT HIT:</b> Events table hit the 1000-row deletion cap. Run retention again or increase LIMIT if backlog persists.';
}

report += `\n\n<b>Timestamp:</b> ${new Date().toISOString()}`;

return [{
  json: {
    report,
    isDbError: false,
    isLimitHit,
    deletedEvents,
    totalEvents,
    eventsTableSize,
    staleCircuitReset,
    schemaVersionPresent,
    expectedTablesFound,
    schemaOk
  }
}];

const item = $input.first().json || {};
const evalData = $('Evaluate Cleanup').first().json || {};
let report = evalData.report || '🧹 <b>DATA RETENTION REPORT</b>\n\nNo cleanup report was generated.';
const analyzeError = !!(item.error && typeof item.error === 'object' && item.error.message);

if (analyzeError) {
  report += `\n\n⚠️ <b>ANALYZE FAILED:</b> <code>${String(item.error.message).substring(0, 500)}</code>`;
} else {
  report += '\n\n✅ <b>ANALYZE:</b> completed successfully.';
}

return [{
  json: {
    ...evalData,
    report,
    analyzeOk: !analyzeError,
    analyzeErrorMessage: analyzeError ? item.error.message : ''
  }
}];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json || {};
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  eventType: item.eventType || 'alert_failed',
  source: 'Data Retention',
  workflowName: 'Data Retention',
  failedNode: item.failedNode || 'unknown',
  reason: item.error?.message || 'Telegram or Postgres delivery failed'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length, droppedCacheCount: staticData.droppedCacheCount || 0 } }];
